const REST = require('./lib/helper/REST');
const JSONResponse = require('./lib/helper/JSONResponse');

// Mock configuration
const restConfig = {
  endpoint: 'https://httpbin.org',
  onRequest: (request) => {
    console.log('onRequest called');
    request.headers['start-time'] = Date.now();
  },
  onResponse: (response) => {
    console.log('onResponse called');
    const startTime = response.config.headers['start-time'];
    const endTime = Date.now();
    const responseTime = endTime - startTime;
    response.headers['x-response-time'] = responseTime;
    console.log(`Response time calculated: ${responseTime}ms`);
  }
};

// Create helpers
const restHelper = new REST(restConfig);
const jsonHelper = new JSONResponse({ requestHelper: 'REST' });

// Mock helpers object
const helpers = {
  REST: restHelper,
  JSONResponse: jsonHelper
};

// Assign helpers to both helpers
restHelper.helpers = helpers;
jsonHelper.helpers = helpers;

// Test the onResponse functionality
async function testOnResponseBug() {
  console.log('Testing onResponse functionality...');

  // Initialize JSONResponse helper
  jsonHelper._beforeSuite();

  // Perform a test request
  try {
    const response = await restHelper.sendGetRequest('/get');

    // Check if headers were modified by onResponse
    console.log('Response headers:', response.headers);
    console.log('Response time header:', response.headers['x-response-time']);

    // Check JSONResponse helper's stored response
    console.log('JSONResponse stored response headers:', jsonHelper.response ? jsonHelper.response.headers : 'undefined');

    if (response.headers['x-response-time']) {
      console.log('✅ SUCCESS: onResponse hook is working');
    } else {
      console.log('❌ FAILURE: onResponse hook did not modify headers');
    }

  } catch (error) {
    console.error('Error during test:', error.message);
  }
}

testOnResponseBug();

