  endpoint: 'https://httpbin.org',
  onRequest: (request) => {
    console.log('onRequest called');
  },
  onResponse: (response) => {
    console.log('onResponse called');
  }
};

const restHelper = new REST(restConfig);
console.log('this.options.onResponse:', restHelper.options.onResponse);
console.log('this.config.onResponse:', restHelper.config.onResponse);
console.log('Are they the same?', restHelper.options.onResponse === restHelper.config.onResponse);

// Test 2: Check the actual bug in _executeRequest method
console.log('\n=== Test 2: Checking _executeRequest method ===');

// Mock the _executeRequest method to test the logic
const originalExecuteRequest = restHelper._executeRequest;
restHelper._executeRequest = async function(request) {
  // Simulate the request processing
  const response = {
    headers: {},
    data: 'test',
    status: 200,
    config: request
  };

  // This is the buggy line - checking this.config.onResponse instead of this.options.onResponse
  console.log('Checking this.config.onResponse:', this.config.onResponse);
  console.log('Checking this.options.onResponse:', this.options.onResponse);

  if (this.config.onResponse) {
    // This line should not execute if the bug exists
    console.log('BEFORE FIX: this.config.onResponse was called (BUG!)');
    await this.config.onResponse(response);
  } else {
    console.log('BEFORE FIX: this.config.onResponse is null (EXPECTED)');
  }

  if (this.options.onResponse) {
    // This line should execute
    console.log('BEFORE FIX: this.options.onResponse was called (SHOULD BE CALLED)');
    await this.options.onResponse(response);
  } else {
    console.log('BEFORE FIX: this.options.onResponse is null (SHOULD NOT HAPPEN)');
  }

  return response;
};

// Test the bug
async function testBug() {
  await restHelper.sendGetRequest('/get');
}

testBug().catch(console.error);

