// Test the full scenario with JSONResponse helper
const REST = require('./lib/helper/REST');
const JSONResponse = require('./lib/helper/JSONResponse');

console.log('=== Testing full scenario: REST + JSONResponse ===');

// Mock the actual scenario from the bug report
const restConfig = {
  endpoint: 'https://httpbin.org',
  onRequest: (request) => {
    console.log('onRequest called');
    request.headers['start-time'] = Date.now();
  },
  onResponse: (response) => {
    console.log('onResponse called');
    const startTime = response.config.headers['start-time'];
    const endTime = Date.now();
    const responseTime = endTime - startTime;
    response.headers['x-response-time'] = responseTime;
    console.log(`Response time calculated: ${responseTime}ms`);
  }
};

const jsonConfig = {
  requestHelper: 'REST'
};

// Create helpers
const restHelper = new REST(restConfig);
const jsonHelper = new JSONResponse(jsonConfig);

// Mock helpers object as it would exist in CodeceptJS
const helpers = {
  REST: restHelper,
  JSONResponse: jsonHelper
};

// Assign helpers to both helpers
restHelper.helpers = helpers;
jsonHelper.helpers = helpers;

async function testFullScenario() {
  console.log('\n=== Initializing helpers ===');

  // Initialize JSONResponse (this would normally be done by CodeceptJS)
  jsonHelper._beforeSuite();

  console.log('\n=== Performing API request ===');

  try {
    // Perform the API request
    await restHelper.sendGetRequest('/get');

    console.log('\n=== Checking results from JSONResponse ===');

    // Check the response stored in JSONResponse helper
    if (jsonHelper.response) {
      console.log('Response available in JSONResponse helper:', jsonHelper.response.status);

      // This mimics the user's code from the bug report
      const responseHeaders = jsonHelper.response.headers;
      console.log(`Response time from headers: ${responseHeaders['x-response-time']} ms`);

      if (responseHeaders['x-response-time']) {
        console.log('✅ SUCCESS: Full scenario works correctly!');
        console.log(`Response time measured successfully: ${responseHeaders['x-response-time']}ms`);
      } else {
        console.log('❌ FAILURE: Response time header missing');
      }
    } else {
      console.log('❌ FAILURE: No response available in JSONResponse helper');
    }

  } catch (error) {
    console.error('Error during test:', error.message);
  }
}

testFullScenario().catch(console.error);

