// Test specifically how JSONResponse connects to REST helper
const REST = require('./lib/helper/REST');

console.log('=== Testing JSONResponse connection to REST helper ===');

const restConfig = {
  endpoint: 'https://httpbin.org',
  onRequest: (request) => {
    console.log('onRequest called');
    request.headers['start-time'] = Date.now();
  },
  onResponse: (response) => {
    console.log('onResponse called');
    const startTime = response.config.headers['start-time'];
    const endTime = Date.now();
    const responseTime = endTime - startTime;
    response.headers['x-response-time'] = responseTime;
    console.log(`Response time calculated: ${responseTime}ms`);
  }
};

async function testConnection() {
  const restHelper = new REST(restConfig);

  // Simulate what JSONResponse does in _beforeSuite()
  console.log('\n=== Simulating JSONResponse _beforeSuite hook ===');

  // This is line 76 from JSONResponse.js - it overwrites the onResponse hook!
  restHelper.config.onResponse = response => {
    console.log('JSONResponse hook called - storing response');
    // This would store the response in JSONResponse
  };

  console.log('Original onResponse:', restConfig.onResponse);
  console.log('Modified onResponse:', restHelper.config.onResponse);

  // Now test if the original onResponse still gets called
  console.log('\n=== Testing if original onResponse still works ===');

  try {
    const response = await restHelper.sendGetRequest('/get');

    console.log('Response headers:', response.headers);

    if (response.headers['x-response-time']) {
      console.log('✅ SUCCESS: Original onResponse still works');
      console.log(`Response time: ${response.headers['x-response-time']}ms`);
    } else {
      console.log('❌ FAILURE: Original onResponse was overwritten by JSONResponse');
    }

  } catch (error) {
    console.error('Error during test:', error.message);
  }
}

testConnection().catch(console.error);

