// Test the actual fix with proper configuration
const REST = require('./lib/helper/REST');

console.log('=== Testing the actual fix: Using options.onResponse instead of config.onResponse ===');

// Since we fixed REST.js to use this.options.onResponse instead of this.config.onResponse,
// JSONResponse can continue to use this.config.onResponse without overwriting user's hooks

const restConfig = {
  endpoint: 'https://httpbin.org',
  onRequest: (request) => {
    console.log('onRequest called - setting start-time header');
    request.headers['start-time'] = Date.now();
  },
  onResponse: (response) => {
    console.log('USER onResponse called - calculating response time');
    const startTime = response.config.headers['start-time'];
    const endTime = Date.now();
    const responseTime = endTime - startTime;
    response.headers['x-response-time'] = responseTime;
    console.log(`User calculated response time: ${responseTime}ms`);
  }
};

async function testRealFix() {
  const restHelper = new REST(restConfig);

  console.log('\n=== Test 1: Basic REST functionality ===');
  console.log('this.options.onResponse:', typeof restHelper.options.onResponse);
  console.log('this.config.onResponse:', typeof restHelper.config.onResponse);

  // Now simulate JSONResponse hook - this should NOT interfere with user's onResponse
  console.log('\n=== Simulating JSONResponse installation ===');

  // JSONResponse would normally do this:
  const originalConfigOnResponse = restHelper.config.onResponse;
  restHelper.config.onResponse = async (response) => {
    console.log('JSONResponse hook called');
    // Store response for JSONResponse functionality
    // Optionally call original if it exists
    if (originalConfigOnResponse) {
      console.log('Calling original config.onResponse');
      await originalConfigOnResponse(response);
    }
  };

  console.log('\n=== Testing REST functionality after JSONResponse configuration ===');

  try {
    const response = await restHelper.sendGetRequest('/get');

    console.log('\nResponse headers:', response.headers);

    // Check if user's onResponse (via options) still worked
    if (response.headers['x-response-time']) {
      console.log('✅ SUCCESS: User\'s onResponse hook via options.onResponse worked!');
      console.log(`Response time: ${response.headers['x-response-time']}ms`);
    } else {
      console.log('❌ FAILURE: User\'s onResponse hook did not work');
    }

    // The fix should make this work because REST.js now uses:
    // this.options.onResponse (user's hook) instead of this.config.onResponse

  } catch (error) {
    console.error('Error during test:', error.message);
  }
}

testRealFix().catch(console.error);

